// src/backend/core/utils/sanitizeBody.ts
var PROTECTED_FIELDS = [
  "customerId",
  "name",
  "email",
  "metadata",
  "stripeId"
];
var sanitizeBody = (body) => {
  const rawBody = body || {};
  const sanitized = {};
  for (const [key, value] of Object.entries(rawBody)) {
    if (!PROTECTED_FIELDS.includes(key)) {
      sanitized[key] = value;
    }
  }
  return sanitized;
};

export {
  sanitizeBody
};
